    "key": "dramatic_interpretation",
    "name": "Dramatic Interpretation (DI)",
    "meta": "High School & Middle School · Max 10 minutes (30-second grace period) · No props or costumes · Published work",
    "guideFile": "Dramatic_Interpretation_Judge_Guide.md",
    "criteria": [
      {
        "key": "literature_selection_and_cutting_quality",
        "name": "Literature Selection & Cutting Quality",
        "whatToEvaluate": "Is the source material appropriate for DI? Does the cutting have dramatic integrity — a clear story with emotional depth and a complete arc?",
        "levels": {
          "excellent": "Published work with literary merit; cutting includes full dramatic arc; material explores genuine human complexity; not overdone or gimmicky",
          "good": "Solid selection; minor cuts feel abrupt; arc mostly present",
          "needs_work": "Material too light for DI; cutting lacks clear story; ending feels incomplete; overly melodramatic or shock-value choices"
        }
      },
      {
        "key": "introduction",
        "name": "Introduction",
        "whatToEvaluate": "Does the intro name the work and author? Does it establish context without over-explaining? Is it engaging and original?",
        "levels": {
          "excellent": "Smoothly transitions from teaser; names work/author; creates emotional stakes; does not spoil the story",
          "good": "All required info present; intro functional but formulaic",
          "needs_work": "Missing author or title; intro over-explains the plot; disconnected from teaser or body"
        }
      },
      {
        "key": "characterization",
        "name": "Characterization",
        "whatToEvaluate": "Can you tell characters apart? Are they consistent? Do they have internal logic (motivation, physicality, voice)?",
        "levels": {
          "excellent": "Each character has a distinct, motivated voice and body; transitions between characters are clean and clear; characters have depth — not caricatures",
          "good": "Characters are distinguishable; some consistency issues; vocal variety present but limited physical differentiation",
          "needs_work": "Characters blend together; transitions are unclear; character choices feel arbitrary or stereotypical"
        }
      },
      {
        "key": "blocking_physical_performance",
        "name": "Blocking / Physical Performance",
        "whatToEvaluate": "Use of the performance space, physical differentiation between characters, focal points (off-stage eye focus), and use of the body to tell the story.",
        "levels": {
          "excellent": "Space used meaningfully; off-stage focus is specific and consistent per character; physical choices reinforce emotional content; movement feels motivated",
          "good": "Some spatial awareness; focal points mostly consistent; movement present but occasionally unmotivated",
          "needs_work": "Performer stays in one spot; looks directly at audience during character dialogue; random or nervous movement"
        }
      },
      {
        "key": "vocal_performance_and_emotional_range",
        "name": "Vocal Performance & Emotional Range",
        "whatToEvaluate": "Vocal variety, emotional authenticity, use of pace and pause, ability to convey the full spectrum of emotion the piece demands.",
        "levels": {
          "excellent": "Wide, natural emotional range; voice carries genuine feeling; pacing honors both intensity and quiet; emotional shifts feel lived-in",
          "good": "Emotional moments present; voice conveys feeling; some stretches feel performed rather than felt",
          "needs_work": "Monotone or emotionally flat; emotions telegraphed without underlying truth; tension or pathos not conveyed"
        }
      },
      {
        "key": "overall_effect_impact",
        "name": "Overall Effect / Impact",
        "whatToEvaluate": "Did the performance achieve what DI is meant to do — illuminate the human condition and create an emotional experience?",
        "levels": {
          "excellent": "Genuinely moving; the audience understands and feels the story; performance lingered",
          "good": "Story was clear and emotionally present; solid but didn't fully break through",
          "needs_work": "Flat or confusing; audience may not have grasped the story's meaning or felt its weight"
        }
      }
    ],
