    "key": "international_extemp",
    "name": "International Extemporaneous Speaking (IX)",
    "meta": "High School Event · 30 minutes prep · Max 7 minutes speech · Delivered from memory · Focus: International / foreign affairs",
    "guideFile": "International_Extemporaneous_Speaking_Judge_Guide.md",
    "criteria": [
      {
        "key": "direct_answer_to_the_question",
        "name": "Direct Answer to the Question",
        "whatToEvaluate": "Does the speech answer the *specific* question as worded on the draw slip? Is the answer (the thesis) stated clearly and early — in the introduction, not built to suspensefully at the end?",
        "levels": {
          "excellent": "Answers the exact question directly; clear, defensible position stated upfront in the Q&A; stays on the question throughout",
          "good": "Answers the question; position present but takes a while to arrive, or drifts toward the general region/topic rather than the precise wording",
          "needs_work": "Vague, avoided, or non-answer; speaks to the broad topic but never takes a position; or answers a different question than the one drawn"
        }
      },
      {
        "key": "analysis_and_reasoning",
        "name": "Analysis & Reasoning",
        "whatToEvaluate": "Beyond stating facts, does the student explain *why* things are happening and what follows? Do they connect evidence to the thesis, weigh causes and effects, and engage the complexity of an international issue — including historical context and cross-border dynamics?",
        "levels": {
          "excellent": "Explains cause-and-effect and significance; links every point back to the thesis; frames the issue with regional or historical context; acknowledges complexity or counterarguments; offers genuine insight, not just a summary of news",
          "good": "Adequate reasoning; evidence is mostly connected to the argument; some moments of real analysis amid description",
          "needs_work": "Speech is a list of facts or a news recap; \"so what?\" never answered; no clear chain of reasoning from evidence to conclusion"
        }
      },
      {
        "key": "evidence_and_source_citation",
        "name": "Evidence & Source Citation",
        "whatToEvaluate": "Are claims backed by specific, credible, current, and varied sources? Does the student cite **source name and date** orally? In IX, expect international and foreign-affairs outlets, and a healthy mix of US-based and international sources.",
        "levels": {
          "excellent": "Multiple credible, recent sources cited by name *and* date; sources are varied (e.g., Council on Foreign Relations, BBC, Foreign Affairs, Foreign Policy, The Economist, Financial Times, Asia Times, Jerusalem Post); blends US and international perspectives; evidence is specific and matches the point it supports",
          "good": "Sources cited and credible; some attributions vague or missing a date; evidence supports the points but lacks variety or leans on a single outlet",
          "needs_work": "Little or no citation; \"studies show\" / \"experts say\" without attribution; outdated or general-knowledge claims only"
        }
      },
      {
        "key": "organization_and_structure",
        "name": "Organization & Structure",
        "whatToEvaluate": "Does the speech follow the Extemp architecture — intro with Q&A and preview, 2–3 balanced body points, conclusion that restates the answer and reviews points? Are transitions and signposting clear?",
        "levels": {
          "excellent": "Clean Q&A → thesis → preview; 2–3 clearly-labeled, roughly equal body points; smooth signposted transitions; conclusion mirrors the intro and reviews the points",
          "good": "Structure present and followable; preview used; transitions functional but occasionally abrupt; points slightly unbalanced",
          "needs_work": "Hard to follow; no clear preview; points blur together or are lopsided; conclusion abrupt or missing"
        }
      },
      {
        "key": "vocal_delivery",
        "name": "Vocal Delivery",
        "whatToEvaluate": "Rate, volume, articulation, and use of pause. Given limited prep, judge charitably — but clarity and confidence still matter. Note that foreign names, places, and terms should be pronounced with reasonable confidence and consistency.",
        "levels": {
          "excellent": "Conversational and confident; pace lets ideas land; meaningful pauses; clear articulation; foreign names and terms handled smoothly; voice conveys engagement with the topic",
          "good": "Mostly clear; some filler words (\"um,\" \"like,\" \"so\"), often at transitions; minor rushing or monotone stretches; occasional hesitation on unfamiliar names",
          "needs_work": "Excessive fillers; pace too fast or halting; mumbled or monotone; foreign terms stumbled over repeatedly; sounds like memorized text being retrieved rather than thought through"
        }
      },
      {
        "key": "physical_delivery_and_fluency",
        "name": "Physical Delivery & Fluency",
        "whatToEvaluate": "Eye contact, posture, gestures, and composure. Does the student look like they are thinking through the argument in real time, or reciting?",
        "levels": {
          "excellent": "Consistent eye contact distributed across the room; purposeful natural gestures; poised, controlled stance; recovers smoothly from any stumble",
          "good": "Generally good eye contact with occasional drift up/away when retrieving information; some gestures; minor nervous habits",
          "needs_work": "Eye contact mostly lost; rigid or fidgety; distracting habits (swaying, pacing); visible memory lapses that derail the flow"
        }
      },
      {
        "key": "overall_effect_persuasiveness",
        "name": "Overall Effect / Persuasiveness",
        "whatToEvaluate": "Did the speech advance a clear, well-supported position on the question? Did you leave intellectually satisfied — with an answer and a perspective on a corner of the world you may not have known well?",
        "levels": {
          "excellent": "Left with a clear answer and a compelling, well-evidenced argument; the student's command of the international issue and its context was evident",
          "good": "Position was clear and the argument solid; research and engagement present but the analysis didn't fully land",
          "needs_work": "Unclear position; felt like a survey of the topic rather than an argument; little sense the student grasped the question's significance or global context"
        }
      }
    ],
